'use client';

import { IconInnerShadowTop } from '@tabler/icons-react';
import * as React from 'react';

import { NavMain } from '@/components/nav-main';
import { NavUser } from '@/components/nav-user';
import {
  Sidebar,
  SidebarContent,
  SidebarFooter,
  SidebarHeader,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
} from '@/components/ui/sidebar';
import { adminSidebarItems, employeeSidebarItems } from '@/lib/sidebar-items';
import { UserRoleEnum } from '@/modules/auth/schema';
import { useAuth } from './auth-handler';

export function AppSidebar({ ...props }: React.ComponentProps<typeof Sidebar>) {
  const { loggedInUser, logout } = useAuth();

  return (
    <Sidebar collapsible='icon' {...props}>
      <SidebarHeader>
        <SidebarMenu>
          <SidebarMenuItem>
            <SidebarMenuButton asChild className='data-[slot=sidebar-menu-button]:p-1.5!'>
              <a href='#'>
                <IconInnerShadowTop className='size-5!' />
                <span className='text-base font-semibold'>Sample Admin Panel</span>
              </a>
            </SidebarMenuButton>
          </SidebarMenuItem>
        </SidebarMenu>
      </SidebarHeader>
      <SidebarContent>
        <NavMain
          items={
            loggedInUser?.role === UserRoleEnum.COMPANY_ADMIN
              ? adminSidebarItems
              : employeeSidebarItems
          }
        />
      </SidebarContent>
      <SidebarFooter>
        {loggedInUser && <NavUser onLogout={logout} user={loggedInUser} />}
      </SidebarFooter>
    </Sidebar>
  );
}
